import { useEffect, useState } from "react";
import { FantasyStat } from '../objects/fantasy-stat';
import { GetAgeGroupFantasyStats } from '../services/fantasy-stat-service';
import FantasyStatTable from '../components/fantasy/fantasy-stat-table';
import FantasyScoringTable from '../components/fantasy/fantasy-scoring';

export default function FantasyStats()
{
    const [stats, setStats] = useState<FantasyStat[] | null>(null);
    
    useEffect(() => {
        GetAgeGroupFantasyStats(9).then(stats => setStats(stats));
    }, []); 
    
    const [sort, setSort] = useState(0);

    function Sort(name : string)
    {
        switch (name)
        {
            case "pts":
                stats?.sort((a , b) => b.totalPoints - a.totalPoints)
                break;

            case "pld":
                stats?.sort((a , b) => b.appsPts - a.appsPts)
                break;

            case "gls":
                stats?.sort((a , b) => b.goalPts - a.goalPts)
                break;

            case "ass":
                stats?.sort((a , b) => b.assistsPts - a.assistsPts)
                break;

            case "gso":
                stats?.sort((a , b) => b.gsoPts - a.gsoPts)
                break;

            case "shots":
                stats?.sort((a , b) => b.shotPts - a.shotPts)
                break;

            case "cs":
                stats?.sort((a , b) => b.cleanSheetPoints - a.cleanSheetPoints)
                break;

            case "saves":
                stats?.sort((a , b) => b.savesPts - a.savesPts)
                break;
        }
        setSort(sort + 1);
    }
    
    return(        
        <div>
            { stats ? 
                <>  
                    <div className='container-fluid'>                        
                        <div className="row">
                            <FantasyStatTable fantasyStats={stats}></FantasyStatTable>
                        </div>  
                        <FantasyScoringTable></FantasyScoringTable>  
                    </div>        
                </> 
            : <p>Loading...</p>}
        </div>                
    )
}
